import{_ as n,o as t,c as i,ai as r}from"./chunks/framework.ampVZV4B.js";const p=JSON.parse('{"title":"数据库连接池与参数调优【初/中级】","description":"","frontmatter":{},"headers":[],"relativePath":"database/connection-pool.md","filePath":"database/connection-pool.md"}'),e={name:"database/connection-pool.md"};function l(s,o,a,c,g,d){return t(),i("div",null,[...o[0]||(o[0]=[r('<h1 id="数据库连接池与参数调优【初-中级】" tabindex="-1">数据库连接池与参数调优【初/中级】 <a class="header-anchor" href="#数据库连接池与参数调优【初-中级】" aria-label="Permalink to “数据库连接池与参数调优【初/中级】”">​</a></h1><hr><h3 id="❓-面试官-为什么项目中要使用数据库连接池-不用会怎样" tabindex="-1">❓ 面试官：为什么项目中要使用数据库连接池？不用会怎样？ <a class="header-anchor" href="#❓-面试官-为什么项目中要使用数据库连接池-不用会怎样" aria-label="Permalink to “❓ 面试官：为什么项目中要使用数据库连接池？不用会怎样？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 使用连接池主要是为了<strong>复用连接，减少频繁创建和销毁连接的开销</strong>，同时能够<strong>控制数据库的最大并发连接数</strong>，防止数据库被高并发流量打垮。</p><p><strong>📝 详细原理解析：</strong> 如果不用连接池（每次需要执行 SQL 时都新建 <code>Connection</code>）：</p><ol><li><strong>网络开销极大</strong>：创建一个 MySQL 连接，需要经过 TCP 三次握手、MySQL 服务端权限校验等多个步骤，耗时远远大于执行一条简单的 <code>SELECT</code> 语句本身。</li><li><strong>资源耗尽风险</strong>：在高并发场景下，如果每个请求都去数据库建连接，MySQL 的可用连接数（<code>max_connections</code>，默认通常只有 151 个）会瞬间被耗尽，导致后续请求全部报 <code>Too many connections</code> 错误。</li></ol><p>引入连接池后：</p><ul><li>在应用启动时，连接池会预先建立一部分空闲连接（<code>minimum-idle</code>）。</li><li>业务需要查数据库时，直接从池子里<strong>借（borrow）</strong>一个现成的连接，用完后<strong>还（return）</strong>给池子，而不是关闭它。</li></ul><hr><h3 id="❓-面试官-目前主流的数据库连接池有哪些-你了解它们的区别吗" tabindex="-1">❓ 面试官：目前主流的数据库连接池有哪些？你了解它们的区别吗？ <a class="header-anchor" href="#❓-面试官-目前主流的数据库连接池有哪些-你了解它们的区别吗" aria-label="Permalink to “❓ 面试官：目前主流的数据库连接池有哪些？你了解它们的区别吗？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 目前最主流的是 <strong>HikariCP</strong> 和 <strong>Druid</strong>。HikariCP 的核心优势是&quot;极致的性能&quot;（Spring Boot 2.0 后的默认选择）；而 Druid（阿里开源）的核心优势是&quot;强大的监控和 SQL 拦截功能&quot;。</p><p><strong>📝 详细对比：</strong></p><ol><li><strong>HikariCP（光速池）</strong>： <ul><li><strong>优点</strong>：号称目前最快的连接池。代码极其精简，通过字节码级别的优化（如 <code>FastList</code> 替代 <code>ArrayList</code>）、并发无锁集合、使用自定义的 <code>ConcurrentBag</code> 等手段将性能压榨到极致。</li><li><strong>缺点</strong>：缺少自带的 UI 监控面板和慢 SQL 统计功能（通常需要借助外部监控如 Prometheus + Grafana）。</li></ul></li><li><strong>Druid（德鲁伊）</strong>： <ul><li><strong>优点</strong>：为监控而生。自带 Web 监控控制台，能直观看到连接池状态、慢 SQL 执行次数、SQL 防注入（WallFilter）等。国内大部分传统老项目和政企项目最爱用。</li><li><strong>缺点</strong>：为了统计和监控，加了很多锁和埋点，性能比 HikariCP 稍微差一点点（但在绝大多数业务场景下，这点性能差异可以忽略不计）。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 选型建议：如果是互联网高并发核心链路服务，且公司有完善的链路追踪监控体系（如 SkyWalking），直接用 SpringBoot 默认的 <strong>HikariCP</strong>；如果是中后台管理系统，排查慢 SQL 比较费劲，建议用 <strong>Druid</strong>，它的监控面板能省去很多排查麻烦。</p><hr><h3 id="❓-面试官-如果线上突然报-connection-is-not-available-或者连接池耗尽-你怎么排查" tabindex="-1">❓ 面试官：如果线上突然报 <code>Connection is not available</code> 或者连接池耗尽，你怎么排查？ <a class="header-anchor" href="#❓-面试官-如果线上突然报-connection-is-not-available-或者连接池耗尽-你怎么排查" aria-label="Permalink to “❓ 面试官：如果线上突然报 Connection is not available 或者连接池耗尽，你怎么排查？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 连接池耗尽（Connection Leak）通常有两个原因：一是<strong>数据库发生了慢查询或死锁</strong>导致连接被长时间占用无法归还；二是<strong>代码里存在&quot;连接泄漏&quot;（比如开启了事务但中途抛出未捕获的异常导致连接没释放）</strong>。</p><p><strong>📝 详细排查步骤：</strong></p><ol><li><strong>先看是不是数据库挂了/慢了</strong>： <ul><li>如果系统平时运行正常，突然报连接池耗尽，90% 的概率是因为数据库里出现了慢查询！</li><li>一个请求拿走连接，本来 10ms 就该还回来，结果因为慢查询执行了 10 秒，这就导致连接被霸占。并发一上来，几十个连接瞬间被借空，后续请求全拿不到连接报错。</li><li><strong>排查手段</strong>：立刻去数据库执行 <code>show processlist;</code>，看是不是有大量正在执行的慢 SQL。</li></ul></li><li><strong>看是不是连接泄漏（代码 Bug）</strong>： <ul><li>排查代码里是不是有耗时极长的 RPC 调用（比如 HTTP 请求）被包在了 <code>@Transactional</code> 事务注解里。</li><li>只要进了 <code>@Transactional</code> 方法，就会立刻从连接池拿走一个连接。如果这个方法里去请求第三方接口花了 5 秒，那么这个数据库连接就被白白挂起占用了 5 秒！</li><li><strong>排查手段</strong>：开启连接池的防泄漏检测机制。例如 HikariCP 可以配置 <code>leakDetectionThreshold=5000</code>（如果一个连接被借走超过 5 秒还没还，就会在日志里打印出借走这个连接的<strong>代码堆栈信息</strong>，能精准定位到哪行代码没还连接）。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong><strong>核心避坑准则</strong>：在实际开发中，我严格遵循<strong>&quot;大事务拆小&quot;</strong>原则。严禁把无关的 RPC 调用、发 MQ 消息、甚至文件上传等耗时操作放在带有 <code>@Transactional</code> 注解的方法内部。我会把这些耗时操作放在事务外执行，只有遇到真正需要落库的代码时，才通过编程式事务或拆分出的小方法去加事务，最大程度缩短占用数据库连接的时间。</p><hr><h3 id="❓-面试官-连接池的核心参数怎么设置-比如-maximum-pool-size-设置多少合适-是越大越好吗" tabindex="-1">❓ 面试官：连接池的核心参数怎么设置？比如 <code>maximum-pool-size</code> 设置多少合适？是越大越好吗？ <a class="header-anchor" href="#❓-面试官-连接池的核心参数怎么设置-比如-maximum-pool-size-设置多少合适-是越大越好吗" aria-label="Permalink to “❓ 面试官：连接池的核心参数怎么设置？比如 maximum-pool-size 设置多少合适？是越大越好吗？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 连接池大小<strong>绝对不是越大越好</strong>！设置过大反而会因为 CPU 频繁的上下文切换和锁竞争导致性能下降。通常推荐的大小是：<strong><code>连接数 = ((核心数 * 2) + 有效磁盘数)</code></strong>。一般单节点配置 10~20 个连接就足够支撑极高的并发了。</p><p><strong>📝 核心参数解析（以 HikariCP 为例）：</strong></p><ol><li><strong><code>maximum-pool-size</code>（最大连接数）</strong>： <ul><li>池中允许的最大连接数（包含空闲和正在使用的）。如果达到上限，新来的请求会被阻塞等待。</li><li>误区：很多人觉得并发 1000 就该设 1000。大错特错！MySQL 服务端是基于线程的，CPU 核心数有限。如果强行弄 1000 个连接同时发 SQL，MySQL 的 CPU 会把大量时间浪费在线程上下文切换上。</li><li>经验值：对于一般的 4 核/8 核服务器，连接池设为 10~30 完全足够。</li></ul></li><li><strong><code>minimum-idle</code>（最小空闲连接数）</strong>： <ul><li>池中始终保持的空闲连接数。HikariCP 建议不要设置，让它和 <code>maximum-pool-size</code> 保持一致，这样可以避免在流量突增时因为临时创建连接而导致的性能抖动（即固定大小的连接池性能最好）。</li></ul></li><li><strong><code>connection-timeout</code>（连接超时时间）</strong>： <ul><li>客户端从池子里借连接时，最多等待多久，超时就抛异常。通常设置为 30000ms（30秒）。</li></ul></li><li><strong><code>idle-timeout</code>（空闲连接超时时间）</strong>： <ul><li>一个连接空闲多久会被池子主动回收释放。通常设置 600000ms（10分钟）。</li></ul></li><li><strong><code>max-lifetime</code>（连接最大存活时间）</strong>： <ul><li>一个连接不管是不是空闲的，只要活过了这个时间，就会被强制回收（防止网络层的静默断开）。必须比数据库的 <code>wait_timeout</code> 小！通常设置 1800000ms（30分钟）。</li></ul></li></ol>',29)])])}const u=n(e,[["render",l]]);export{p as __pageData,u as default};
